20	// Runes and moonstones are "components" — a distinct pricing tier that shares
21	// one base premium (and, later, block/alike rules). Naming the shared value
22	// makes the equality intentional rather than a coincidence two entries happen
23	// to share.
24	const COMPONENT_BASE_PREMIUM = 25;
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	// A "building block" of exactly this many alike components is offered at a
27	// special block premium instead of the per-component price.
28	const COMPONENT_BLOCK_SIZE = 3;
29	const COMPONENT_BLOCK_PREMIUM = 60;
30	
31	const BASE_PREMIUMS: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: COMPONENT_BASE_PREMIUM,
37	  moonstone: COMPONENT_BASE_PREMIUM,
38	};
39	const PROCESSING_FEE = 5;
40	
41	// Surcharges are expressed as integer percentages and applied as
42	// `amount * percent / 100`, keeping the maths in integers (avoids float errors
43	// such as `100 * 1.1 === 100.00000000000001`).
44	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
45	const CURSE_SURCHARGE_PERCENT = 50;
46	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
47	const HIGH_ENCHANTMENT_MIN_LEVEL = 5;
48	const LOYALTY_DISCOUNT_PERCENT = 20;
49	const LOYALTY_MIN_YEARS = 2;
50	const FOLLOWUP_CONTRACT_DISCOUNT_PERCENT = 15;
51	const FIRST_CONTRACT_INDEX = 0;
52	
53	const percentOf = (amount: number, percent: number): number =>
54	  (amount * percent) / 100;
55	
56	// A surcharge that applies only when a condition holds, expressed as a
57	// percentage of some base amount (and 0 otherwise).
58	const conditionalPercent = (
59	  applies: boolean,
60	  amount: number,
61	  percent: number,
62	): number => (applies ? percentOf(amount, percent) : 0);
63	
64	// The base premium for a given item type, with unknown types priced at 0.
65	// This is the single point that reads BASE_PREMIUMS, so both per-item and
66	// per-group pricing share one definition of "the base price of a type".
67	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
68	
69	// A single item's base premium. Block pricing is a group-level concern handled
70	// separately in sumBasePremiums, so a plain per-type lookup suffices here.
71	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
72	
73	// Item-specific surcharges, each a percentage of the item's own base premium:
74	// a curse adds 50%, and a highly-enchanted item (level >= 5) adds 30%. They
75	// stack when both apply.
76	const itemSurcharge = (item: Item): number => {
77	  const base = itemBasePremium(item);
78	  const curse = conditionalPercent(
79	    item.cursed ?? false,
80	    base,
81	    CURSE_SURCHARGE_PERCENT,
82	  );
83	  const highEnchantment = conditionalPercent(
84	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_MIN_LEVEL,
85	    base,
86	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
87	  );
88	  return curse + highEnchantment;
89	};
90	
91	const sumItemSurcharges = (items: Item[]): number =>
92	  items.reduce((total, item) => total + itemSurcharge(item), 0);
93	
94	const countByType = (items: Item[]): Map<string, number> => {
95	  const counts = new Map<string, number>();
96	  for (const item of items) {
97	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
98	  }
99	  return counts;
100	};
101	
102	const componentGroupPremium = (count: number): number =>
103	  count === COMPONENT_BLOCK_SIZE
104	    ? COMPONENT_BLOCK_PREMIUM
105	    : count * COMPONENT_BASE_PREMIUM;
106	
107	const typeGroupPremium = (type: string, count: number): number =>
108	  COMPONENT_TYPES.has(type)
109	    ? componentGroupPremium(count)
110	    : count * basePremiumForType(type);
111	
112	const sumBasePremiums = (items: Item[]): number =>
113	  [...countByType(items)].reduce(
114	    (total, [type, count]) => total + typeGroupPremium(type, count),
115	    0,
116	  );
117	
118	// Policy-wide modifiers scale with the whole policy's base premium.
119	// First-insurance is a surcharge every new policy pays; the loyalty discount
120	// rewards customers at or past the loyalty threshold.
121	const firstInsuranceSurcharge = (policyBase: number): number =>
122	  percentOf(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
123	
124	const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
125	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS
126	    ? percentOf(policyBase, LOYALTY_DISCOUNT_PERCENT)
127	    : 0;
128	
129	// Every contract after the customer's first quote in the scenario is a
130	// follow-up contract and earns a discount.
131	const followUpDiscount = (quoteIndex: number, policyBase: number): number =>
132	  quoteIndex > FIRST_CONTRACT_INDEX
133	    ? percentOf(policyBase, FOLLOWUP_CONTRACT_DISCOUNT_PERCENT)
134	    : 0;
135	
136	export const quote = (
137	  customer: Customer,
138	  step: QuoteStep,
139	  quoteIndex: number,
140	): QuoteResult => {
141	  const policyBase = sumBasePremiums(step.items);
142	  const premium = Math.ceil(
143	    policyBase +
144	      sumItemSurcharges(step.items) +
145	      firstInsuranceSurcharge(policyBase) -
146	      loyaltyDiscount(customer, policyBase) -
147	      followUpDiscount(quoteIndex, policyBase) +
148	      PROCESSING_FEE,
149	  );
150	  return { premium };
151	};
152	
153	export const claim = (): unknown => {
154	  return undefined;
155	};
